import{_ as p,o as A,c as e,j as r,a as B,a1 as a}from"./chunks/framework.Bp7r_-XI.js";const i=JSON.parse('{"title":"特殊技能","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/特殊技能.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/特殊技能.md"}'),C={name:"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/特殊技能.md"};function t(D,b,n,o,s,d){return A(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"特殊技能",tabindex:"-1"},[B("特殊技能 "),r("a",{class:"header-anchor",href:"#特殊技能","aria-label":'Permalink to "特殊技能"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),a('<h1 id="特殊技能-1" tabindex="-1">特殊技能 <a class="header-anchor" href="#特殊技能-1" aria-label="Permalink to &quot;特殊技能&quot;">​</a></h1><p>FATE能力组（特殊技能）<br> 描述：出自型月系列世界观，本能力组为该世界观内从者具有的相关能力，在购买后主神会将其赋予给轮回者，使轮回者获得近似的能力。<br> 若无特殊说明，则该能力组中所有技能使用差价升级购买（超过下一等级所需分数的部分将忽略不计）。<br> 若无特殊说明，则该能力组中所有技能的效果为高等级替换低等级。</p><p>健硕（D，C，B，A）<br> 价格：D+1000/C+1500/B+2500/A+4000<br> 分类：被动<br> 描述：与生俱来的特别的顽健性。即使在战场上也没怎么受过伤，从出生以来就没有生过病，这样逸话的技能化。可以提升耐久的参数，减少受到攻击时的伤害，其中也也包含了对毒素与疾病的耐受力。<br> 效果：<br> 根据技能等级，获得D/C/B/A级毒素与疾病来源效果的免疫能力。<br> 在D级时，你的生命值上限提升2点。<br> 在C级时，你的生命值上限提升3点。<br> 在B级时，你的生命值上限提升3点，同时获得2点基于天生防御的全伤害吸收的效果。<br> 在A级时，你的生命值上限提升自身耐力属性三分之一的数值，同时获得2点基于天生防御的全伤害吸收的效果。<br> ——</p><p>耐毒（D，C，B，A）<br> 价格：500/D+1000/C+1500/B+2500<br> 分类：被动<br> 描述：生物肉体对毒素的抗性，也具有提高受到治疗效果的能力。<br> 效果：<br> 根据技能等级，你获得D/C/B/A级毒素来源效果的免疫。<br> 在无支线等级时，该能力提供选择自身一项快速医疗池扩大8点的效果。D，C，B级则依次提供额外1/2/4点的快速医疗效果，对应医疗池12/24/48点。</p><p>快速拔枪（C，B，A）<br> 价格：D+1000/C+1000/B+2500（逐级）<br> 描述：将射击中的速射进行特化的技术。有着甚至可以看到对方拔枪之后再拔枪却还能抢先射中对方的程度的技巧。是快枪手(Sharpshooter)所拥有的技能。<br> 效果：<br> 根据技能等级，你在进行射击攻击时获得D/C/A级措手不及的效果（对应D/C/B级）。在D级时，你的远程攻击不再因触及范围内而导致高速减半。<br> 【拔枪】效果生效以后，除非人物以移动动作进行一次【炫技换弹】，否则人物本场景内无法再享受【拔枪】特性所带来的好处（无限子弹可以正常炫技换弹）。你可以正常的将换弹行为结合其中，但如果你原本的换弹动作高于自由动作，则需要额外支付4XP习惯这种换弹方式。<br> ——<br> 你可以额外消费10分购买枪套，枪套体积会等同于选定武器的体积，能且仅能容纳购买时指定的武器。<br> ——<br> 在C级时，除了保留之前等级的效果外：当你进行先攻投掷时/所有角色行动轮开始前，你可以进行一个不计算其他属性加值的敏捷检定决定你的拔枪速度，如此检定被称为拔枪检定；接着将拔枪检定成功数加入先攻。<br> 对于先攻低于你的敌人，你在进行攻击时可以将拔枪检定成功数加入其中。以此法获得的加值均为速度加值。你在拔枪检定后的当轮内必须进行攻击。<br> 【枪斗术】：仅当你不持盾，不身着重甲时，你所持处于枪套中的武器便视为具有【格挡3】。<br> 以下特性选择一项获得：<br> *你在执行炫技换弹时，可同时以手中武器进行一次格挡。<br> *你在执行炫技换弹时，可同时进行一次移动。<br> ——<br> B级不提供特殊效果，但是保留之前所有等级的效果，同时提供的措手不及等级更高（见上述）。</p><p>反骨之相（A）<br> 价格：C+1500<br> 分类：被动<br> 描述：不会逗留在同一个地方，也不会拥戴同一个君主的天性。不适合亲自当君主，亦无法找到自己君主的流浪之星。<br> 效果：<br> 你在全检定上获得等同自身传奇决心*1点增强加值。<br> ——<br> 若处于型月世界观下，同时作为从者，则你需要在 3天内杀死自身的御主（若有）。<br> 若处于型月世界观下，同时作为从者，则你可以最多无视1划令咒带来的命令效果，在御主死亡后能行动的时间为：御主剩余令咒数*1 天。可以重新缔结契约，但仍旧需要在新的倒计时内弑主。<br> ——<br> 当盟友中具有不低于反骨等级的领导力技能时，反骨副作用暂时无效。</p><p>暴风雨的航海家（B，A，A+）<br> 价格：B+2000/A+4500/S+8000<br> 描述：驱使被理解为船的东西的才能。由于也需要作为集团领袖的能力，所以也兼备了军事谋略、统率力效果的特殊技能。<br> 效果：<br> 驾驶【船】类载具时，你获得该技能等级-1级的【领导力】和【军略】（但军略最高等级依旧是B）。<br> 在S级时，该能力将军略范围扩大到等同自身的敏感范围生效，同时直接获得军略下属升级后获得的效果。<br> 【因此获得的额外技能（领导力，军略）不会获得自由属性。】<br> 【购买该能力的S级不会获得自由属性。】</p><p>背水一战（C）<br> 价格：C+2000<br> 动作：迅捷动作<br> 消耗：1点意志力<br> 持续：一场景<br> 目标：自身<br> 描述：置身于绝境当中，能够爆发出强大的战斗力。<br> 效果：持续时间内，当你没有完好生命值，且最好的生命值为严重时，你不会因为伤势而昏迷，同时在攻击/防御上获得5点表现加值/闪避防御，以及1个攻击/防御上的附加成功。</p><p>人剑合一/剑术（A）<br> 价格：B+2500<br> 分类：被动<br> 描述：一个人和剑契合，剑相当于身体的一部分，能够在你的操控下运用自如，就像是你的手一样灵活。<br> 技能效果：<br> 你在使用武技下属刀剑类专业相关检定时，获得等同于自身沉着附加*2点修行加值，以及等同传奇沉着*1个额外附加成功。<br> 同时获得：【静如止水】<br> 【静如止水】：当受到心灵来源的效果影响时，若该影响等级不超过B级，则自动将其免疫。<br> ——</p><p>宗和的心得（C，B，A）<br> 价格：C+1000/B+2500/A+4500<br> 分类：见下<br> 描述：即使对同一个对手重复同样的招式多少次，命中精准度也不会下降的特殊技能。也就是说是拥有“变得不会被敌人看穿攻击”效果的能力。<br> 效果：<br> 若你的攻击会造成额外次数的多次攻击减值，则将至多【敏捷属性】点多次攻击减值转变为等量的【高速】，这表现为你的攻击绝对不会被看破。<br> 当你重复使用一项招式时，你可以事先使用一个移动动作进行准备，使下一次攻击附带B/A/S级措手不及效果。<br> ——<br> 在C级时，若对应用了这一措手不及的攻击的结果不满意，则可以进行一次重骰 必须接受第二次结果。<br> 在B级时，除了具有上一级的效果外，同时攻击附带额外的【高速10】。<br> 在A级时，除了具有之前等级的效果外，若在计算目标防御后该能力提供的高速仍有剩余，则可以将剩余高速转为等量的技艺加值。<br> 画面表现上，虽然对方在第一次遭受此技能时不会得到任何提示，但在对方第二次见识时将会发觉“你的招式难以看穿”。</p><p>巨兽狩猎（B，A）<br> 价格：D+500/C+1000（逐级）<br> 分类：被动<br> 描述：亚瑟与蹂躏不列颠的诸巨兽作战，并将其悉数击倒。是表示具有丰富的「与巨大敌性生物作战的经验」的技能。<br> 效果：<br> 在D级时，你获得执行绊摔/冲撞/擒抱行为时，可以无视体积带来的优势与劣势的能力。<br> 在C级时，你在攻击体型大于10的目标时额外具有接触攻击的效果。</p><p>秀丽容颜（C+）<br> 价格：B+2000<br> 分类：被动<br> 描述：从服装到外貌、肉体，都散发着难以置信之美（不仅仅是外表）的谜样氛围。不论是和男性还是女性进行交渉，判定时都能施以正面补正。 此外，也能无视以特定性别为对象的效果。<br> 效果：<br> 你在计算效果与前提上，性别总是视为男女取优计算。此外，你可以以当前的风度数值重新决定一次基础外貌，在进行交涉相关检定时获得5DP内在加值，与1个额外附加成功数。</p><p>谍报搜查（C，B，A）<br> 价格：D+1500/C+1500/B+2000<br> 动作：整轮动作<br> 持续：一场景<br> 目标：见下<br> 描述：这个技能并不是将自身的气息遮断，而是让敌对者无法感知气息，同时利用假情报使敌人混乱。<br> 抵达A级后只要从友方阵营无人告发，敌对者就几乎不可能有所察觉。<br> 效果：<br> 持续期间，根据技能等级获得D/C/B级特异本质反侦测能力。在D级时，你的攻击附带D级心灵来源的混乱效果，命中后目标使用意志豁免伤害出目，失败则目标在该场景内无法辨别敌我，随机进行攻击目标选择。<br> 在C级时，该来源将升级为C级心灵来源。在B级时，除了将来源升级位B级心灵来源外，同时使混乱效果改为胁迫+支配效果。命中后目标使用意志豁免伤害出目，失败则目标在该场景内必须优先选择队友进行攻击。<br> 若场景内不存在队友，则目标可以正常攻击敌人，但仍然无法选择攻击你，即使是AOE性质的攻击也会有意避开，或无法使用。</p><p>圈境（B）<br> 价格：B+2000<br> 动作：移动动作<br> 目标：见下<br> 持续：一轮<br> 描述：中华之理。用气感知周围的状况，并抹消自身存在的技法。达到极致时能与天地合一，甚至能让自身自然地变得透明。随着年龄增长，该技法完成了进一步的进化。哪怕在交战状态下，也能在瞬间消失无踪。<br> 效果：<br> 在回合外受到攻击时，你可以反射动作立刻进行一次移动，移动距离等同自身基础移动距离，本次移动视为B级别、幻像来源的传送效果并具有【打断性】。在完成移动后，你获得持续一轮的B级特异本质反侦测能力。<br> 在画面表现上，你在面对攻击时忽然消失无踪，从而进行对于攻击的规避。</p><p>高速神言（A）<br> 价格：S+8000<br> 描述：不使用咒文或连接魔术回路就能够发动魔术的能力。瞬间契约（TenCount），能以一工程（Single Action）的时间启动大魔术。辅佐魔术咏唱的技能。通常，魔术的规模越变得大就越需要冗长的咏唱，但通过此技能，能够大幅度缩短咏唱。于使用直接攻击魔术时十分有效。<br> 持有高速神言的术者只要有足够的魔力，就可以连发出强力的魔术攻击。&quot;神言&quot;是各个神话时代所使用，也就是上级咒文言语。通常而言，人类的发声器官无法再现。<br> 效果：每轮开始时，你额外获得14点AP。但这14点AP将单独拆分为8（标准动作）+4（移动动作）+2（迅捷动作），用于释放消费不同动作的法术。因此，这一效果提供的AP无法使用整轮动作才能释放的法术。<br> 你在使用法术时具有S级先制。<br> 此外，你在学识技能下开启一个特殊的专业【神言】，你现在可以将【神言】结合在施法检定中，与通常专业加值不同的是，每1级【神言】可以使施法检定增加1DP专业加值、1点高速、1点破魔。</p><p>钢铁般的决意（C，B，A，EX）<br> 价格：D+500/C+1000/B+2000/A+4000<br> 分类：被动<br> 描述：是在有如地狱一般的经历中培养出的钢铁般的精神力化成的技能。<br> 效果：<br> 根据技能等级，你获得D/C/B/A级心灵来源效果的免疫，以及在意志豁免上获得6/12/20/【决心】*2点修行加值。此外，该能力会在使用决心属性进行的相关检定中，提供0/1/4/5点修行加值。</p><p>武艺（D，C，B，A，EX）<br> 价格：暂不开放<br> 描述：哪怕是英雄的武术技艺，也足以成为贯彻其英雄事迹本身的恢宏传说，甚至是超越其之上流传于万千后世而升华为宝具的超凡技巧。<br> 囊括着世间上存在的所有由人类自身所创造的武术技艺，无论是响彻世界的中国功夫，亦或是藏匿于世界背面的名不经传的奇术都算作此内。<br> 效果：-</p><p>无穷的武炼（A）<br> 价格：B+2000<br> 分类：被动<br> 描述：在某个时代号称无双的武艺洗练，使心技体的完全合一，不受任何精神影响就能发挥出强大的战斗能力。同时还要精通数种兵器，并能适应各种战斗风格。<br> 效果：<br> 你可以从下列效果中选择3项武装战斗风格，获得对应的效果，但同时生效的效果总是只有一种，且必须使用武装战斗风格对应的武器。<br> 【刀剑】你进行的近战攻击检定获得等同自身传奇力量*1个额外附加成功。<br> 【长柄】当你使用长柄武器进行攻击时，触及距离提升等同自身传奇敏捷*10米，同时在进行格挡中获得1个额外的防御附加成功。<br> 【弓弩】你造成的最终伤害提升等同自身传奇力量*1点。<br> 【鞭】你的近战攻击附带2点不可豁免的纠缠不良点数，可叠加。<br> 【锤棍】你的近战攻击增加等同自身【传奇力量-1】*5点破甲效果。<br> 【短刃】你的攻击附带B级措手不及效果。或者你可以在购买时将其改为增加等同自身【传奇敏捷-1】*5点高速效果。<br> 【斧】你的近战攻击增加等同自身【传奇力量】*5点破甲效果，但最多只能因此获得10点。若计算目标防御后该能力提供的破甲仍有剩余，则转换为等量的攻击检定上的增强加值。<br> 【拳脚】你的近战攻击增加等同自身【传奇力量】*5点威猛效果，但最多只能因此获得10点。若计算目标防御后该能力提供的威猛仍有剩余，则转换为等量的攻击检定上的增强加值。<br> 【暗器】你的攻击附带B级措手不及效果。或者你可以在购买时将其改为：你的投掷攻击增加等同自身【传奇敏捷】*5点高速效果，但最多只能因此获得10点。若计算目标防御后该能力提供的高速仍有剩余，则转换为等量的攻击检定上的增强加值。<br> 【盾牌】你现在可以使用自由动作进行格挡。<br> 【枪械】你视为具有了【射击B】的效果。</p><p>军师的忠言（C，B，A）<br> 价格：C+1000/B+2000/A+5000<br> 动作：标准动作<br> 消耗：无<br> 范围：15/15+传奇智力*10/15+传奇智力*50米<br> 目标：所有友方单位（包括自身）<br> 持续：一场景<br> 描述：能对战况进行分析，并给予对我方形势有用的建议。等级越高准确性越高。等级A+的情况下可以把意外事态在内、进行 100%预测。不过主神提供的版本只有战斗性能的部分。<br> 效果：<br> 标准动作启动，范围内所有友方单位（包括自身）根据技能等级获得6/12/20点洞察防御，同时获得2/6/0点临时生命，持续一场景。<br> 在A级时，该能力将会提供基于洞察防御的【适应】与【超级坚韧】特性。<br> ——<br> 在A级时，该能力虽然不会提供临时生命，但会提供受到致死伤害时的免疫效果，这是一个A级别环境来源的无敌效果，在画面表现上通过分析战况利用环境阻碍了致命的攻击（免疫致死伤害的效果，在每影片中只会生效一次）。</p><p>弑神者（D，C，B）<br> 价格：C+1000/B+2000/A+4000<br> 动作：自由动作<br> 目标：见下<br> 持续：一轮<br> 描述：超越人身、杀死神明的传说。屠杀了众多神灵的她的生存之道所具现的技能拥有对神灵的特效，对神灵、死灵、持有神性技能的Servant拥有攻击补正。<br> 效果：<br> 消费自由动作启动，在持续时间内，你根据技能等级，无视不超过该技能等级的【神性】效果（即C/B/A级），这一效果对于主神空间内的兑换无效。<br> 在C级时，仅限于针对神明，你在进行攻击时额外具有【湮灭】特性。<br> 在B级时，仅限于针对神明，你在进行攻击时额外具有【湮灭】【幻灭】特性。<br> 在A级时，仅限于针对神明，你在进行攻击时额外具有【湮灭】【幻灭】特性。同时每轮一次，你对其进行的攻击成功数增加一半计算。</p><p>屠龙者（C，B，A）<br> 价格：C+1000/B+2000/A+4000<br> 动作：自由动作<br> 目标：见下<br> 持续：一轮<br> 描述：击杀龙种者所具备的特殊技能之一。对龙种的攻击力、防御力会大幅上升。此非天赐的才能，可说是将屠龙的逸话本身技能化了。<br> 效果：<br> 消费自由动作启动，在持续时间内，你根据技能等级，无视不超过该技能等级的【龙种】效果（即C/B/A级），这一效果对于主神空间内的兑换无效。<br> 在C级时，仅限于针对龙，你在进行攻击时额外具有【湮灭】特性。<br> 在B级时，仅限于针对龙，你在进行攻击时额外具有【湮灭】【幻灭】特性。<br> 在A级时，仅限于针对龙，你在进行攻击时额外具有【湮灭】【幻灭】特性。同时每轮一次，你对其进行的攻击成功数增加一半计算。</p><p>神迹（D，C，B，A，A++，EX）<br> 价格：1000/D+500/C+1000/B+2000/A+4000/S+8000<br> 分类：被动<br> 描述：尽管圣堂教会禁止学习司祭所使用的洗礼咏唱以外的魔术，不过这其实只是对外的说辞。部分代行者会被以“奇迹”这种体面的名义教授以强化和念话为首的等等实用性魔术。他们管自己用的魔力叫“祈祷之力”。<br> 如果是从者的话，说不定会将这份“奇迹”升华至“神迹”的程度。<br> 如果到 EX 等级说不定能施展出让原本密布于天空的乌云与持续降落的大雨驱散化作朗朗晴空，又或是做到劈开海洋的程度。<br> 效果：<br> 在无支线等级时，该技能只提供3DP的指定一项神术技能检定上的修行加值。<br> 从D级开始，你选择一项神术技能，该技能等级提升1/2/4/8级。若此时技能等级已经抵达了5/8/11/14，则将提升等级的效果改为在对应神术技能检定上取得1/2/4/4个附加成功，A级会额外因此提供9DP的神术技能检定上的修行加值（对应D/C/B/A级）。<br> ——<br> D级时，你的神术攻击检定若不具有【法破】，则获得【法破】。<br> C级时，每轮一次，使用神术技能检定时若对结果不满意，则可以进行一次重骰，必须接受第二次结果。<br> B级时，每轮一次，使用神术技能检定时若对结果不满意，则可以进行一次重骰，取高。<br> A级时，每轮一次，使用神术技能检定时可以使成功数增加一半。<br> ——<br> S级需要单独购买，可以直接改变当前场景的环境。你需要在购买时从环境规则中挑选最终合计等级不超过S级的环境效果，自由组合。<br> 当你使用该能力后，从下一轮开始时，该场景内环境立刻变更为你在购买时所选择过的环境，这是一个S级命运来源的环境效果，可以满足其他资源的环境前提。</p><p>信仰的加护（D，C，B，A，A+++）<br> 价格：1000/D+1000/C+1000/B+2000/A+4000<br> 描述：只有曾为一个宗教观牺牲的人会拥有的技能。虽然说是加护，但是并没有<br> 来自最高存在的恩惠。有的只是从信心而生的，自己精神与肉体的绝对性而已……太高的话将会造成人格异变。<br> 效果：<br> 根据技能等级（对应D/C/B/A级），分别提供D/C/B/A级心灵来源的效果免疫。<br> 根据技能等级（无支线/D/C/B/A），分别提供1/2/3/6/12点【护盾】。<br> 该护盾仅针对非同宗教信仰的单位生效。</p><p>【护盾】<br> 护盾将提供等同护盾数值*1点的偏斜防御，以及等额的临时生命，这些临时生命在一场战斗中若被击毁，则不会再恢复直至这场战斗结束。<br> 在这场战斗结束后，护盾将会缓慢恢复它带有的临时生命，以每20分钟恢复1点的速度自动恢复，也可以使用快速医疗对它进行加速治疗。<br> 在对抗擒抱检定时，护盾此时每剩余1点未被击毁的临时生命，就会额外提供1点对抗擒抱检定上的力量加值。</p><p>启示（EX）<br> 价格：A+4000<br> 描述：直感是战斗中的第六感，但“启示”适用于所有关乎到目标达成的事象（例如在旅途中选择最适合的道路）。<br> 效果：<br> 你免疫S级措手不及效果，当你陷入突袭轮后，可以反射动作进行一次攻击或者全防御。<br> 你能够知晓如何寻找并不复杂的目标： 1、每日至多传奇感知次，当你知晓一个具有明确指向的物品、人物时，可以知道这一词汇所指代的目标最后所出现的地点或是这一词汇出现的残缺影像。但这些事件必须简洁到类似：从东南西北中进行选择，其中一个方向是通往最近城镇的方向，你在不知道最近城镇在哪的时候从中选择一个方向想要抵达，则一定会正确选中哪个方向。<br> 2、进行一次类似抛硬币、掷骰（注意这是非检定意义上的掷骰）的行为时，你总是能猜中正面或反面或是知道投出数目。<br> 这是一个A级命运来源的预言效果。若ST认为该效果过于模糊，则可以禁用此效果的作用。<br> 选开：ST可以随性地给予该技能持有者一些模糊的情报，这些情报会如同神启一般带有难以琢磨的色彩，需要自行参悟。<br> 【启示不能与心眼真，心眼伪，或直感技能同时具有。】</p><p>骑士的誓言（C，B，A）<br> 价格：C+1000/B+2000/A+5000<br> 动作：反射动作<br> 距离：触及距离/见下<br> 目标：单一/范围<br> 持续：一次<br> 描述：对御主宣誓效忠，同时也深得御主的信任。保护弱者是骑士的准则之一，在你力竭或倒下之前你将不会让任何人伤害到你所宣誓保护之人。<br> 效果：<br> 在C级时，你可以在触及范围内任一友方单位受到攻击时，使用反射动作给予该单位全遮蔽效果，该效果具有【打断性】。<br> 在B级时，你可以在15米范围内任一友方单位受到攻击时，使用反射动作给予范围内所有友方单位全遮蔽效果，该效果具有【打断性】。<br> 在A级时，你可以在5米范围内任一友方单位受到攻击时，使用反射动作给予范围内所有友方单位全遮蔽效果，该效果具有【打断性】，且此时你具有【强拦截】效果。若承受了致命伤害，则你可以免疫那次伤害，这是一个A级祝福来源的无敌效果，每影片只会生效一次。</p><p>骑士不徒手而亡（A）<br> 价格：B+2000<br> 分类：被动<br> 描述：能够赋予手中的武器宝具属性并能加以驱使。兰斯洛特能用宝具的限度是要能够认知判别为“武器”的范围内（比如说尽管战斗机可以化为宝具但航空母舰被认知为“运送武器的东西”因而无法宝具化）。<br> 效果：<br> 你所持有的任何物品，道具都能化为武装，它们作为临时武器而言具有15L的武器伤害提升，使用你的武技+下属任意一项专业进行攻击。你必须在购买时选择一种大类的武器转化：如投掷武器，近战武器等，你无法将物品，道具转化作为未选择大类型的临时武器使用。<br> 若使用临时武器具有减值，则你最多可以抵消不超过3点对应减值。此外，你使用的临时武器具有【法破】特性。</p><p>魔力放出（色）（A）<br> 价格：A+4000<br> 动作：标准动作<br> 范围：敏感范围<br> 目标：见下<br> 持续：见下<br> 描述：从服装到外貌、肉体，都散发着难以置信之色气（不仅仅是外表）的谜样氛围。不论是怎样坚毅的英雄，都会被其放出的色气所折服。<br> 效果：<br> 你进行一次攻击检定，对自身敏感范围内的所有敌对目标进行攻击，目标需要使用意志豁免伤害，伤害类型为精神类型伤害。你可以选择不造成伤害而只令对方进行意志豁免，DC为此次攻击原本应造成的伤害值，失败则陷入A级心灵来源的迷情状态，迷情状态将持续一场景。</p><p>人间观察（A）<br> 等级：S+8000<br> 分类：被动<br> 描述：对人们进行观察，并予以理解的技术。不单纯只是进行观察，对陌生人们的生活和喜好甚至人生加以猜想，并将其铭记于心的记忆力是很重要的。<br> 效果：<br> 你可以通过观察，理解，猜测的方式直接了解他人当下的心理活动与想法，情绪。甚至可以通过猜想过去的方法了解对方的人生轨迹。<br> 这是一个S级心灵来源的读心/过去视效果，无需进行实际对抗。</p><p>纵使三度迎接夕阳（A）<br> 价格：S+8000<br> 分类：被动<br> 描述：由她临死前经历三次落日一事演变而来的技能。从尼禄死前的逸话中诞生的技能。<br> 传说尼禄自刎身亡三天后，在发现她的罗马士兵为她盖上布时曾一度睁开眼睛，并出言慰劳他们。<br> 效果：你可以免疫受到的伤害，这是一个S级祝福来源的效果，每日最多只会触发这个效果三次。<br> 该效果会在每日的落日结束后恢复次数，因此一些影片中可能会导致该能力的次数无法恢复，而改变环境的效果则对该能力没有作用。<br> 【购买该技能不会获得自由属性。】</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',32)])])}const _=p(C,[["render",t]]);export{i as __pageData,_ as default};
